from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # Use the subject of the first triple as the main entity
    subject = triples[0].subject

    # Gather information by predicate
    info: dict[str, str] = {}
    for t in triples:
        # keep the first occurrence of each predicate
        if t.predicate not in info:
            info[t.predicate] = t.object

    parts: list[str] = []

    # Basic identification
    if "category" in info:
        parts.append(f"{subject} is a {info['category']}")
    else:
        parts.append(subject)

    # Location information
    location_elements = []
    for key in ("municipality", "district", "nearestCity", "state", "country"):
        if key in info:
            location_elements.append(info[key])
    if location_elements:
        parts.append("located in " + ", ".join(location_elements))

    # Dates
    date_map = {
        "established": "established on",
        "foundingDate": "founded on",
        "inaugurationDate": "inaugurated on",
    }
    for pred, phr in date_map.items():
        if pred in info:
            parts.append(f"{phr} {info[pred]}")

    # Designer / Owner
    if "designer" in info:
        parts.append(f"designed by {info['designer']}")
    if "owner" in info:
        parts.append(f"owned by {info['owner']}")
    elif "owningOrganisation" in info:
        parts.append(f"owned by {info['owningOrganisation']}")

    # Dedication
    if "dedicatedTo" in info:
        parts.append(f"dedicated to {info['dedicatedTo']}")

    # Additional attributes (optional, can be extended)
    for pred, phr in (
        ("material", "made of"),
        ("nativeName", "known locally as"),
        ("leader", "led by"),
        ("leaderTitle", "holding the title of"),
    ):
        if pred in info:
            parts.append(f"{phr} {info[pred]}")

    # Assemble the final sentence
    sentence = ", ".join(parts) + "."
    return sentence

# EVOLVE-BLOCK-END

